# -*- coding: utf-8 -*-
# Supporting reference content for AstroHype. Field shapes match the engine exactly.

GLOSSARY = [
 {"term":"Asteroid","cat":"Solar System","def":"A small rocky body that orbits the Sun, most found in the belt between Mars and Jupiter."},
 {"term":"Astronomical unit","cat":"Measurement","def":"The average distance from Earth to the Sun, about 150 million kilometres."},
 {"term":"Atmosphere","cat":"Planets","def":"The layer of gases held around a world by its gravity."},
 {"term":"Aurora","cat":"Phenomena","def":"Glowing lights near a planet's poles caused by particles from the Sun hitting the air."},
 {"term":"Axis","cat":"Motion","def":"The imaginary line through a planet's poles that it spins around."},
 {"term":"Big Bang","cat":"Cosmology","def":"The leading theory that the universe began hot and dense and has been expanding for about 13.8 billion years."},
 {"term":"Black hole","cat":"Exotic objects","def":"A region where gravity is so strong that not even light can escape."},
 {"term":"Celestial sphere","cat":"Sky","def":"An imaginary dome of sky around Earth used to map where objects appear."},
 {"term":"Comet","cat":"Solar System","def":"An icy body that grows a glowing head and tail when it nears the Sun."},
 {"term":"Constellation","cat":"Sky","def":"One of 88 official regions of the sky, traditionally seen as a star pattern."},
 {"term":"Corona","cat":"The Sun","def":"The Sun's faint outer atmosphere, visible during a total solar eclipse."},
 {"term":"Cosmic microwave background","cat":"Cosmology","def":"Faint leftover radiation from the early universe, evidence for the Big Bang."},
 {"term":"Cosmology","cat":"Cosmology","def":"The study of the universe as a whole, its origin, structure and fate."},
 {"term":"Crater","cat":"Surfaces","def":"A bowl-shaped pit made when a space rock strikes a world's surface."},
 {"term":"Dark energy","cat":"Cosmology","def":"An unknown influence that is causing the universe's expansion to speed up."},
 {"term":"Dark matter","cat":"Cosmology","def":"Invisible matter detected only by its gravity, far more common than ordinary matter."},
 {"term":"Declination","cat":"Coordinates","def":"A star's north-south position in the sky, similar to latitude on Earth."},
 {"term":"Dwarf planet","cat":"Solar System","def":"A round world orbiting the Sun that shares its zone with other bodies, like Pluto."},
 {"term":"Eclipse","cat":"Phenomena","def":"When one body's shadow falls on another, as in a solar or lunar eclipse."},
 {"term":"Ellipse","cat":"Motion","def":"A stretched oval, the true shape of an orbit."},
 {"term":"Escape velocity","cat":"Motion","def":"The speed needed to break free of a world's gravity for good."},
 {"term":"Event horizon","cat":"Exotic objects","def":"The boundary of a black hole, past which nothing can return."},
 {"term":"Exoplanet","cat":"Other worlds","def":"A planet that orbits a star other than our Sun."},
 {"term":"Galaxy","cat":"Galaxies","def":"A huge system of stars, gas, dust and dark matter held together by gravity."},
 {"term":"Gas giant","cat":"Planets","def":"A large planet made mostly of gas, like Jupiter or Saturn."},
 {"term":"Globular cluster","cat":"Star groups","def":"An ancient, tightly packed ball of hundreds of thousands of stars."},
 {"term":"Gravity","cat":"Forces","def":"The attractive force between any two objects that have mass."},
 {"term":"Habitable zone","cat":"Other worlds","def":"The region around a star where a planet could have liquid water."},
 {"term":"Kuiper Belt","cat":"Solar System","def":"A broad ring of icy bodies beyond Neptune, home to Pluto and many small worlds."},
 {"term":"Light-year","cat":"Measurement","def":"The distance light travels in one year, about 9.5 trillion kilometres."},
 {"term":"Lunar eclipse","cat":"Phenomena","def":"When the Moon passes into Earth's shadow and often turns red."},
 {"term":"Magnitude","cat":"Measurement","def":"A number measuring brightness, where smaller means brighter."},
 {"term":"Main sequence","cat":"Stars","def":"The long, stable stage when a star fuses hydrogen in its core."},
 {"term":"Meteor","cat":"Phenomena","def":"The streak of light made when a bit of space dust burns up in the atmosphere."},
 {"term":"Meteorite","cat":"Solar System","def":"A piece of space rock that survives its fall and lands on the ground."},
 {"term":"Milky Way","cat":"Galaxies","def":"The barred spiral galaxy that contains our Solar System."},
 {"term":"Moon","cat":"Solar System","def":"A natural object that orbits a planet, dwarf planet or asteroid."},
 {"term":"Nebula","cat":"Deep sky","def":"A cloud of gas and dust in space, where stars are born or where they die."},
 {"term":"Neutron star","cat":"Exotic objects","def":"An incredibly dense stellar core left behind by a supernova."},
 {"term":"Nuclear fusion","cat":"Stars","def":"Joining light atoms into heavier ones, the process that powers stars."},
 {"term":"Oort Cloud","cat":"Solar System","def":"A vast spherical shell of comets far surrounding the Solar System."},
 {"term":"Orbit","cat":"Motion","def":"The curved path one object follows around another under gravity."},
 {"term":"Phase","cat":"The Moon","def":"The shape of the Moon's lit part as seen from Earth, from new to full."},
 {"term":"Planet","cat":"Solar System","def":"A large round world that orbits the Sun and has cleared its path of other objects."},
 {"term":"Planetary nebula","cat":"Stars","def":"A glowing shell of gas puffed off by a dying Sun-like star."},
 {"term":"Pulsar","cat":"Exotic objects","def":"A fast-spinning neutron star that sweeps beams of radiation past us."},
 {"term":"Quasar","cat":"Galaxies","def":"The blazing core of a distant galaxy, powered by a giant black hole."},
 {"term":"Red giant","cat":"Stars","def":"A dying Sun-like star that has swelled to enormous size."},
 {"term":"Redshift","cat":"Cosmology","def":"The reddening of light from objects moving away from us as space expands."},
 {"term":"Right ascension","cat":"Coordinates","def":"A star's east-west position in the sky, similar to longitude on Earth."},
 {"term":"Solar System","cat":"Solar System","def":"The Sun together with everything bound to it by gravity."},
 {"term":"Solar wind","cat":"The Sun","def":"A constant stream of particles flowing outward from the Sun."},
 {"term":"Spiral galaxy","cat":"Galaxies","def":"A galaxy with arms winding out from a central bulge, like the Milky Way."},
 {"term":"Star cluster","cat":"Star groups","def":"A group of stars that formed together and stay near one another."},
 {"term":"Supernova","cat":"Stars","def":"The explosive death of a massive star, briefly outshining a galaxy."},
 {"term":"Telescope","cat":"Tools","def":"An instrument that gathers light or radio waves to reveal distant objects."},
 {"term":"Terrestrial planet","cat":"Planets","def":"A small, rocky planet like Mercury, Venus, Earth or Mars."},
 {"term":"White dwarf","cat":"Stars","def":"The small, dense, fading core left when a Sun-like star dies."},
]

